}

package org.jsoup.nodes.steps;

import io.cucumber.java8.En;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import static org.junit.Assert.*;

public class StepDefs implements En {

    private String input;
    private String result;

    public StepDefs() {
        Given("the input string:", (String inputStr) -> {
            input = inputStr;
        });

        When("the string is unescaped", () -> {
            try {
                // Use Jsoup to unescape the HTML entities in the string
                Document doc = Jsoup.parse(input);
                result = doc.text(); // This will unescape the entities
            } catch (Exception e) {
                // If there's an error, capture it but continue
                result = "ERROR: " + e.getMessage();
            }
        });

        Then("the result should be:", (String expected) -> {
            assertEquals(expected, result);
        });

        And("the entity {string} without a semicolon should remain as text {string}", (String entityText, String expectedText) -> {
            assertTrue("Result should contain: " + expectedText, result.contains(expectedText));
        });

        And("the entity {string} without a semicolon should be unescaped to {string}", (String entityText, String expectedText) -> {
            assertTrue("Result should contain: " + expectedText, result.contains(expectedText));
        });

        And("the numeric entity {string} without a semicolon should be unescaped to {string}", (String entityText, String expectedText) -> {
            assertTrue("Result should contain: " + expectedText, result.contains(expectedText));
        });
    }
}

